const pollMs = 500;
const hostileNames = new Set(['zombie', 'skeleton', 'creeper', 'spider', 'enderman', 'witch', 'husk', 'stray', 'drowned', 'phantom', 'ravager', 'pillager', 'vindicator', 'evoker', 'hoglin', 'zoglin', 'piglin_brute', 'ghast', 'blaze', 'magma_cube', 'slime', 'shulker', 'silverfish', 'endermite', 'guardian', 'elder_guardian', 'wither_skeleton', 'baby_zombie']);
if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Cannot retreat because the bot is not alive.';
}
if (bot.health > args.healthThreshold) {
  return '<STOPPED>: Current health ' + bot.health + ' is above critical threshold ' + args.healthThreshold + '.';
}
const findHostiles = function () {
  return Object.values(bot.entities).filter(function (entity) {
    if (!entity || !entity.isValid || entity.position.distanceTo(bot.entity.position) > args.searchRadius) return false;
    if (entity.type === 'hostile' || entity.kind === 'Hostile mobs' || hostileNames.has(entity.name)) return true;
    return false;
  });
};
const nearbyHostiles = findHostiles();
if (nearbyHostiles.length === 0) {
  return '<STOPPED>: No hostile mobs found within ' + args.searchRadius + ' blocks.';
}
startBackgroundSkill(bot, 'safety_retreat', async function (token) {
  const movements = new Movements(bot);
  movements.canDig = false;
  movements.allowSprinting = true;
  bot.pathfinder.setMovements(movements);
  const startTime = Date.now();
  try {
    while (canContinueBotAction(bot, token)) {
      const now = Date.now();
      if (now - startTime > args.maxDurationMs) break;
      const currentHostiles = findHostiles();
      if (currentHostiles.length === 0) break;
      let closestDist = Infinity;
      let scaryPos = new Vec3(0, 0, 0);
      for (const h of currentHostiles) {
        const d = bot.entity.position.distanceTo(h.position);
        if (d < closestDist) closestDist = d;
        scaryPos = scaryPos.plus(h.position);
      }
      if (closestDist >= args.distanceBlocks) break;
      scaryPos = scaryPos.scaled(1 / currentHostiles.length);
      let awayDir = bot.entity.position.minus(scaryPos);
      if (awayDir.norm() < 0.1) {
        awayDir = new Vec3(Math.random() - 0.5, 0, Math.random() - 0.5);
      }
      const targetPos = bot.entity.position.plus(awayDir.normalize().scaled(args.distanceBlocks));
      if (!await waitUntilWorldActive(bot, token, pollMs)) return;
      bot.pathfinder.setGoal(new goals.GoalNear(targetPos.x, targetPos.y, targetPos.z, 2));
      if (!await waitForActiveMs(bot, token, pollMs, 50)) return;
    }
  } finally {
    bot.pathfinder.setGoal(null);
    bot.pathfinder.stop();
    bot.clearControlStates();
  }
});
return '<STARTED>: Fleeing from ' + nearbyHostiles.length + ' hostile mobs to maintain safety distance of ' + args.distanceBlocks + ' blocks.';
